import KeychainAccess

public protocol KeychainServiceType: Sendable {

    func value(key: KeychainService.Key, service: KeychainService.Service) -> String?
    func value(key: KeychainService.Key, service: KeychainService.Service) -> Data?
    func value<T: Codable>(key: KeychainService.Key, service: KeychainService.Service) throws -> T

    func save(string: String, for key: KeychainService.Key, service: KeychainService.Service)
    func save(codable: Codable, for key: KeychainService.Key, service: KeychainService.Service) throws
    func save(data: Data, for key: KeychainService.Key, service: KeychainService.Service)

    func remove(service: KeychainService.Service) throws
    func remove(key: KeychainService.Key, service: KeychainService.Service) throws
}

public class KeychainService: KeychainServiceType, @unchecked Sendable {

    public enum Service: String, CustomStringConvertible {

        case user = "user"
        case oauth = "oauth"

        public var description: String {
            InfoPlistHelper.bundleIdentifier! + "." + self.rawValue
        }
    }

    public enum Key: String, CustomStringConvertible {

        case password = "password"
        case accessToken = "accessToken"
        case refreshToken = "refreshToken"
        case configuration = "configuration"

        public var description: String {
            return self.rawValue
        }
    }

    // MARK: Get values from Keychain
    public func value(key: KeychainService.Key, service: KeychainService.Service) -> String? {

        let keychain = Keychain(service: service.description)
        return keychain[key.description]
    }

    public func value(key: KeychainService.Key, service: KeychainService.Service) -> Data? {

        let keychain = Keychain(service: service.description)
        return keychain[data: key.description]
    }

    public func value<T: Codable>(key: KeychainService.Key, service: KeychainService.Service) throws -> T {

        let keychain = Keychain(service: service.description)
        let data = keychain[data: key.description]
        let codable = try JSONDecoder().decode(T.self, from: data)
        return codable
    }

    // MARK: Save values to Keychain
    public func save(string: String, for key: KeychainService.Key, service: KeychainService.Service) {

        let keychain = Keychain(service: service.description)
        keychain[key.description] = string
    }

    public func save(codable: Codable, for key: KeychainService.Key, service: KeychainService.Service) throws {

        let data = try JSONEncoder().encode(codable)
        self.save(data: data, for: key, service: service)
    }

    public func save(data: Data, for key: KeychainService.Key, service: KeychainService.Service) {

        let keychain = Keychain(service: service.description)
        keychain[data: key.description] = data
    }

    // MARK: Delete values from Keychain

    public func remove(service: KeychainService.Service) throws {

        let keychain = Keychain(service: service.description)
        try keychain.removeAll()
    }

    public func remove(key: KeychainService.Key, service: KeychainService.Service) throws {

        let keychain = Keychain(service: service.description)
        try keychain.remove(key.description)
    }
}

