import Foundation

public class UserDefaultsHelper {

    public static var configuration: String? {

        if let remote = managed.configuration, !remote.isEmpty {
            return remote
        } else if let local = UserDefaults.standard.string(forKey: Keys.configuration), !local.isEmpty {
            return local
        } else {
            return nil
        }
    }

    public static var serverUrl: URL? {

        guard let string = UserDefaults.standard.string(forKey: Keys.serverUrl), let url = URL(string: string) else {
            return nil
        }

        return url
    }

    public static var username: String? {
        return UserDefaults.standard.string(forKey: Keys.username)
    }

    public static var password: String? {
        return UserDefaults.standard.string(forKey: Keys.password)
    }

    public static var pollingInterval: TimeInterval? {

        guard let interval = UserDefaults.standard.string(forKey: Keys.pollingInterval), let double = Double(interval) else {
            return nil
        }

        return double
    }

    public static var timeoutAfter: TimeInterval? {

        guard let timeout = UserDefaults.standard.string(forKey: Keys.timeoutAfter), let double = Double(timeout) else {
            return nil
        }

        return double
    }
}

extension UserDefaultsHelper {

    // Set value in user defaults
    public static func set(_ value: Any, for key: String) {
        return UserDefaults.standard.set(value, forKey: Keys.configuration)
    }

    // Remove all user defaults settings
    public static func removeAll() {

        let appDomain = Bundle(for: UserDefaultsHelper.self).bundleIdentifier!
        UserDefaults.standard.removePersistentDomain(forName: appDomain)
    }

    // Remove specific value in user defaults
    public static func remove(key: String) {
        UserDefaults.standard.removeObject(forKey: key)
    }
}

extension UserDefaultsHelper {

    struct Keys {
        static let pollingInterval = "POLLING_INTERVAL"
        static let timeoutAfter = "TIMEOUT_AFTER"

        static let serverUrl = "SERVER_URL"
        static let username = "USERNAME"
        static let password = "PASSWORD"

        static let configuration = "CONFIGURATION"
        static let managed = "com.apple.configuration.managed"
    }
}

extension UserDefaultsHelper {

    public struct managed {

        public static var dictionary: [String: Any]? {
            return UserDefaults.standard.dictionary(forKey: Keys.managed)
        }

        public static var isManaged: Bool {

            return !(UserDefaultsHelper.managed.configuration?.isEmpty ?? true)
        }

        public static var configuration: String? {

            guard let dictionary = UserDefaultsHelper.managed.dictionary else {
                return nil
            }

            return dictionary[Keys.configuration] as? String
        }
    }
}
